                </div>

                <div className="flex-1 overflow-y-auto p-4">
                    {lowStockProducts.length === 0 ? (
                        <div className="text-center py-10 text-slate-400">
                            <Check size={48} className="mx-auto mb-2 text-green-500 opacity-50"/>
