                   {modalType === 'import' ? <ArrowDown className="text-green-600"/> : modalType === 'export' ? <ArrowUp className="text-red-600"/> : modalType === 'transfer' ? <ArrowRight className="text-blue-600"/> : <Save className="text-orange-600"/>}
