  const subStatuses: Order['subStatus'][] = ['unprocessed', 'printed', 'packed'];
  const carriers = ['SPX Express', 'J&T Express', 'Giao Hàng Nhanh', 'Viettel Post', 'Ninja Van'];
  const customers = ['Nguyễn Văn Anh', 'Trần Thị Bình', 'Lê Văn Chính', 'Phạm Minh Đạo', 'Hoàng Thu Thủy', 'Vũ Quốc Bảo', 'Đặng Ngọc Lan', 'Bùi Xuân Huấn', 'Trịnh Công Sơn', 'Đỗ Mỹ Linh'];

  return Array.from({ length: count }).map((_, i) => {
    // Distribute statuses logically
    let status: Order['status'] = 'processing';
    if (i < 20) status = 'pending';
    else if (i < 50) status = 'processing';
    else if (i < 70) status = 'shipping';
    else if (i < 90) status = 'delivered';
    else if (i < 95) status = 'cancelled';
    else status = 'returned';

    const platform = platforms[i % platforms.length] as any;
    const isExpress = Math.random() > 0.8;
    const dateDay = 10 + (i % 5);
    const orderDate = `10:${30 + (i % 20)} ${dateDay}/05/25`;
    const shipByDate = `${10 + (i % 20)}:00 ${dateDay + 1}/05/25`;

    const itemsCount = 1 + (i % 3);
    const orderItems: OrderItem[] = Array.from({ length: itemsCount }).map((_, idx) => {
      const p = MOCK_PRODUCTS[idx % MOCK_PRODUCTS.length];
      return {
        productId: p.id,
        name: p.name,
        image: p.image,
        sku: p.sku,
        variant: idx % 2 === 0 ? 'Màu Đen, Size L' : 'Màu Trắng, Size M',
        quantity: 1 + (idx % 2),
        price: p.price
      };
    });

    const total = orderItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);

    return {
      id: `${platform.toString().substring(0, 2).toUpperCase()}${100000 + i}`,
      customerName: customers[i % customers.length],
      customerPhone: `09${Math.floor(10000000 + Math.random() * 90000000)}`,
      platform: platform,
      shopId: `sh${(i % 3) + 1}`,
      date: orderDate,
      shipByDate: status === 'processing' || status === 'pending' ? shipByDate : undefined,
      total: total + 30000,
      shippingFee: 30000,
      platformFee: Math.floor(total * 0.1),
      tax: Math.floor(total * 0.015),
      profit: Math.floor(total * 0.25),
      status: status,
      subStatus: status === 'processing' ? subStatuses[i % subStatuses.length] : undefined,
      shippingCarrier: carriers[i % carriers.length],
      shippingMethod: isExpress ? 'Hỏa tốc' : 'Nhanh',
      isCOD: Math.random() > 0.2,
      trackingCode: status !== 'pending' ? `VN${Math.floor(100000000 + Math.random() * 900000000)}` : undefined,
      note: i % 7 === 0 ? 'Giao giờ hành chính, gọi trước khi đến.' : undefined,
      items: orderItems
    };
  });
};

