                <Printer size={12} /> In đơn
              </button>
              <button className="flex-1 bg-indigo-600 text-white text-[10px] py-1.5 rounded hover:bg-indigo-700 font-bold transition-colors shadow-sm flex items-center justify-center gap-1">
                <Package size={12} /> Gói hàng
